webMI.data.subscribe("10.10.12.151/$dev$.Light status Parameters | /LS", function(e) {
var id = "id_375";
var value = e.value;
if (value == true)
	webMI.gfx.setVisible(id, true);
if (value == false)
	webMI.gfx.setVisible(id, false);

});













webMI.data.subscribe("10.10.12.151/$dev$.Heez Status (0 = OFF, 1 = Start-up, 2 = Normal operation, 3 = Night time operation, 4 = Reactivation from night time operation, 5 = Open door, 6 = Control) Parameters | rSt", function(e) {
var id = "id_5";
var value = e.value;
if (value == 0)
	webMI.gfx.setFillOpacity(id, "0.25");
if (value == 1)
	webMI.gfx.setFillOpacity(id, "0.25");
if (value == 2)
	webMI.gfx.setFillOpacity(id, "0.25");
if (value == 3)
	webMI.gfx.setFillOpacity(id, "1");
if (value == 4)
	webMI.gfx.setFillOpacity(id, "0.25");
if (value == 5)
	webMI.gfx.setFillOpacity(id, "0.25");
if (value == 6)
	webMI.gfx.setFillOpacity(id, "0.25");
if (value == 4)
	webMI.gfx.setFillOpacity(id, "0.25");

});



